CREATE TABLE IF NOT EXISTS enterprise_risks(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,code text NOT NULL,title text NOT NULL,description text NOT NULL DEFAULT '',category text NOT NULL,owner text NOT NULL,status text NOT NULL DEFAULT 'identified',inherent_likelihood int NOT NULL CHECK(inherent_likelihood BETWEEN 1 AND 5),inherent_impact int NOT NULL CHECK(inherent_impact BETWEEN 1 AND 5),inherent_score int NOT NULL,inherent_band text NOT NULL,residual_likelihood int NOT NULL CHECK(residual_likelihood BETWEEN 1 AND 5),residual_impact int NOT NULL CHECK(residual_impact BETWEEN 1 AND 5),residual_score int NOT NULL,residual_band text NOT NULL,review_at timestamptz,assessed_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,code));
CREATE TABLE IF NOT EXISTS enterprise_risk_kris(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,risk_id uuid NOT NULL,name text NOT NULL,unit text NOT NULL,threshold numeric NOT NULL,current_value numeric NOT NULL,status text NOT NULL,measured_at timestamptz NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS enterprise_risk_treatments(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,risk_id uuid NOT NULL,owner text NOT NULL,response text NOT NULL,plan text NOT NULL,status text NOT NULL DEFAULT 'planned',due_at timestamptz,completed_at timestamptz,evidence jsonb NOT NULL DEFAULT '[]'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_enterprise_risk_heatmap ON enterprise_risks(tenant_id,status,residual_likelihood,residual_impact);CREATE INDEX IF NOT EXISTS idx_enterprise_kri_status ON enterprise_risk_kris(tenant_id,status);CREATE INDEX IF NOT EXISTS idx_enterprise_treatment_due ON enterprise_risk_treatments(tenant_id,status,due_at);
